#include <coroutine>
#include <vector>

struct Task {
    struct promise_type {
        Task get_return_object() { return {}; }
        std::suspend_never initial_suspend() { return {}; }
        std::suspend_never final_suspend() noexcept { return {}; }
        void return_void() {}
        void unhandled_exception() {}
    };
};

class DataProcessor {
private:
    Task processValue(int value) {
        if (value > 1000) {
            co_await processLargeValue(value);
        } else if (value > 100) {
            co_await processMediumValue(value);
        } else {
            co_await processSmallValue(value);
        }
    }

    Task processVipValue(int value, bool hasSpecialHandling) {
        if (hasSpecialHandling) {
            try {
                co_await processValue(value);
            } catch (const std::exception& e) {
                if (e.what() == "critical") {
                    throw;
                }
            }
        } else {
            co_await processNormalVip(value);
        }
    }

public:
    // Compliant: Lower cognitive complexity
    Task processDataStream(std::vector<int> data, bool isVip, bool hasSpecialHandling) {
        for (auto& value : data) {
            if (value <= 0) continue;

            if (isVip) {
                co_await processVipValue(value, hasSpecialHandling);
            }

            co_await std::suspend_always{};
        }
    }
};
